    if (sent[key]) { stats.skipped++; continue; }

    const meeting = getMeetingInfo(ev);
    const fmtTime = (iso) => iso ? new Date(iso).toLocaleTimeString('en-GB', { hour: '2-digit', minute: '2-digit', timeZone: CONFIG.timezone }) : null;
    const startTime = fmtTime(startISO);
    const endTime = fmtTime(ev.end?.dateTime || ev.end?.date);

    const attendees = (ev.attendees || [])
      .filter(a => !a.self && a.responseStatus !== 'declined')
      .map(a => {
        const name = a.displayName || a.email?.split('@')[0] || '?';
        const icon = a.responseStatus === 'accepted' ? '✓' : a.responseStatus === 'tentative' ? '?' : '';
        return icon ? `${name}${icon}` : name;
      }).slice(0, 5);

    const urgencyEmoji = minsUntil <= 5 ? '🔴' : minsUntil <= 15 ? '🟠' : minsUntil <= 30 ? '🟡' : '🟢';
    const priority = minsUntil <= 5 ? 5 : minsUntil <= 15 ? 4 : minsUntil <= 30 ? 3 : 2;

    let msg = `${urgencyEmoji} *${win.label} - Calendar*\n`;
    msg += `\n📅 *${esc(ev.summary || 'Untitled Event')}*\n`;
    msg += `🕒 ${startTime}${endTime ? ' - ' + endTime : ''} (in ${minsUntil}min)\n`;
    if (ev.organizer && !ev.organizer.self) msg += `👔 ${esc(ev.organizer.displayName || ev.organizer.email?.split('@')[0])}\n`;
    if (attendees.length > 0) {
      msg += `👥 ${attendees.join(', ')}`;
      if ((ev.attendees || []).length > 5) msg += ` +${ev.attendees.length - 5}`;
      msg += `\n`;
    }
    if (!meeting.hasVideo && ev.location) msg += `📍 ${esc(ev.location)}\n`;
    if (meeting.hasVideo) msg += `\n🎥 [Join ${meeting.platform}](${meeting.link})\n`;
    if (ev.htmlLink) msg += `[View in Calendar](${ev.htmlLink})`;

    sent[key] = now;
    stats.sent++;
    out.push({ json: { source: 'calendar', reminderMessage: msg, shouldSendReminder: true, eventId, priority, timestamp: now } });
  } catch (e) {
    stats.errors++;
    console.error(`Calendar error: ${e.message}`);
  }
}

console.log(`Calendar: ${stats.processed} processed, ${stats.sent} sent, ${stats.skipped} skipped, ${stats.errors} errors`);
return out.length > 0 ? out : [{ json: { shouldSendReminder: false, source: 'calendar' } }];

const items = $input.all();
items.sort((a, b) => (b.json.priority || 0) - (a.json.priority || 0));
const MAX_PER_RUN = 5;
if (items.length > MAX_PER_RUN) {
  console.log(`Rate limiting: ${items.length} reminders, sending top ${MAX_PER_RUN}`);
  return items.slice(0, MAX_PER_RUN);
}
return items;

const staticData = $getWorkflowStaticData('global');
if (!staticData.deliveryLog) staticData.deliveryLog = [];
if (!staticData.failedQueue) staticData.failedQueue = [];
if (!staticData.dailyStats) staticData.dailyStats = { date: '', sent: 0, failed: 0, retried: 0 };

const now = Date.now();
const todayStr = new Date(now).toISOString().slice(0, 10);
const result = $json;
const originalMsg = $('Sort & Rate Limit').item.json;
const success = !result.error && result.message_id;

// Reset daily stats at midnight
if (staticData.dailyStats.date !== todayStr) {
  staticData.yesterdayStats = { ...staticData.dailyStats };
  staticData.dailyStats = { date: todayStr, sent: 0, failed: 0, retried: 0 };
}

// Log delivery
staticData.deliveryLog.push({ timestamp: now, success, source: originalMsg.source, subject: originalMsg.subject || originalMsg.eventId || 'unknown' });
if (staticData.deliveryLog.length > 100) staticData.deliveryLog = staticData.deliveryLog.slice(-100);

const outputs = [];

if (success) {
  staticData.dailyStats.sent++;
} else {
  staticData.dailyStats.failed++;
  staticData.failedQueue.push({
    message: originalMsg.reminderMessage,
    source: originalMsg.source,
    attempt: 1,
    maxAttempts: 3,
    queuedAt: now,
    lastError: JSON.stringify(result).substring(0, 200)
  });
  console.error('Send failed, queued for retry');
}

// Process retry queue
const stillWaiting = [];
for (const item of staticData.failedQueue) {
  const waitMs = item.attempt * 60000;
  if (now - item.queuedAt >= waitMs && item.attempt <= item.maxAttempts) {
    item.attempt++;
    item.queuedAt = now;
    staticData.dailyStats.retried++;
    outputs.push({ json: { reminderMessage: '🔄 *Retry (attempt ' + item.attempt + '/' + item.maxAttempts + ')*\n\n' + item.message, isRetry: true } });
    if (item.attempt <= item.maxAttempts) stillWaiting.push(item);
  } else if (item.attempt <= item.maxAttempts) {
    stillWaiting.push(item);
  } else {
    console.error('Permanently failed after ' + item.maxAttempts + ' attempts: ' + item.source);
  }
}
staticData.failedQueue = stillWaiting;

// Daily summary at ~8 AM Israel time
const israelHour = parseInt(new Date(now).toLocaleString('en-GB', { hour: 'numeric', hour12: false, timeZone: 'Asia/Jerusalem' }));
if (israelHour === 8 && staticData.yesterdayStats?.date) {
  if (!staticData.dailySummarySent) staticData.dailySummarySent = {};
  if (!staticData.dailySummarySent[todayStr]) {
    const ys = staticData.yesterdayStats;
    if (ys.sent > 0 || ys.failed > 0) {
      const rate = ys.sent + ys.failed > 0 ? Math.round((ys.sent / (ys.sent + ys.failed)) * 100) : 100;
      let summary = '📊 *Daily Reminder Summary*\n';
      summary += '\n✅ Sent: ' + ys.sent;
      summary += '\n❌ Failed: ' + ys.failed;
      if (ys.retried > 0) summary += '\n🔄 Retried: ' + ys.retried;
      summary += '\n📈 Success rate: ' + rate + '%';
      if (ys.failed > 0) {
        const fails = staticData.deliveryLog.filter(l => !l.success).slice(-3).map(l => '  • ' + l.source + ': ' + l.subject).join('\n');
        if (fails) summary += '\n\n⚠️ *Recent failures:*\n' + fails;
      }
      outputs.push({ json: { reminderMessage: summary, isDailySummary: true } });
      staticData.dailySummarySent[todayStr] = true;
    }
  }
  // Clean old flags
  for (const d of Object.keys(staticData.dailySummarySent || {})) {
    if (d < new Date(now - 259200000).toISOString().slice(0, 10)) delete staticData.dailySummarySent[d];
  }
}

// Clean old failed queue items
staticData.failedQueue = staticData.failedQueue.filter(i => now - i.queuedAt < 86400000);

return outputs.length > 0 ? outputs : [{ json: { delivered: success, noAction: true } }];
